   593|const MOON_EMOJIS: Record<MoonPhase['phase'], string> = {
   594|  new: '🌑',
   595|  waxing_crescent: '🌒',
   596|  first_quarter: '🌓',
   597|  waxing_gibbous: '🌔',
   598|  full: '🌕',
