   602|};
   603|
   604|export function getMoonPhase(date: Date = new Date()): MoonPhase {
   605|  // Reference new moon: January 6, 2000 at 18:14 UTC
   606|  const knownNewMoon = new Date('2000-01-06T18:14:00Z');
   607|  
   608|  // Synodic month (lunar cycle) in milliseconds
   609|  const synodicMonth = 29.530588853 * 24 * 60 * 60 * 1000;
   610|  
   611|  const daysSinceNewMoon = (date.getTime() - knownNewMoon.getTime()) / (24 * 60 * 60 * 1000);
   612|  const lunarAge = daysSinceNewMoon % synodicMonth;
   613|  const normalizedAge = (lunarAge / synodicMonth) * 8;
   614|  
   615|  const phaseIndex = Math.floor(normalizedAge) % 8;
   616|  const phase = MOON_PHASES[phaseIndex];
   617|  
   618|  // Calculate illumination (0-100%)
   619|  const illumination = Math.round((1 - Math.cos((lunarAge / synodicMonth) * 2 * Math.PI)) * 50);
   620|  
   621|  // Days until full moon
   622|  const daysUntilFull = lunarAge < synodicMonth / 2 
   623|    ? Math.round((synodicMonth / 2) - lunarAge) / (24 * 60 * 60 * 1000)
   624|    : Math.round(synodicMonth - lunarAge) / (24 * 60 * 60 * 1000);
   625|  
   626|  // Days until new moon
   627|  const daysUntilNew = Math.round((synodicMonth - lunarAge) / (24 * 60 * 60 * 1000));
   628|  
   629|  const labels: Record<MoonPhase['phase'], string> = {
   630|    new: 'New Moon',
   631|    waxing_crescent: 'Waxing Crescent',
   632|    first_quarter: 'First Quarter',
   633|    waxing_gibbous: 'Waxing Gibbous',
   634|    full: 'Full Moon',
   635|    waning_gibbous: 'Waning Gibbous',
   636|    last_quarter: 'Last Quarter',
   637|    waning_crescent: 'Waning Crescent'
   638|  };
   639|  
   640|  return {
   641|    phase,
   642|    illumination,
   643|    daysUntilFull: Math.round(daysUntilFull),
   644|    daysUntilNew,
   645|    emoji: MOON_EMOJIS[phase],
   646|    label: labels[phase]
   647|  };
   648|}
   649|
   650|export function getMoonPhaseForForecast(forecast: ForecastDay[]): MoonPhase[] {
   651|  return forecast.slice(0, 14).map(day => getMoonPhase(new Date(day.date)));
