    27|// Helper function to estimate growing zone from zip code
    28|export const getGrowingZoneFromZip = (zipCode: string): string | undefined => {
    29|  const zipNum = parseInt(zipCode.substring(0, 3), 10);
    30|  
    31|  if (zipNum >= 0 && zipNum <= 99) return "5b"; // New England
    32|  if (zipNum >= 100 && zipNum <= 199) return "6b"; // Mid-Atlantic
    33|  if (zipNum >= 200 && zipNum <= 299) return "7b"; // VA, Carolinas
    34|  if (zipNum >= 300 && zipNum <= 399) return "8b"; // Deep South
    35|  if (zipNum >= 400 && zipNum <= 499) return "6a"; // Midwest
    36|  if (zipNum >= 500 && zipNum <= 599) return "4b"; // Northern Midwest
    37|  if (zipNum >= 600 && zipNum <= 699) return "5b"; // Central Midwest
    38|  if (zipNum >= 700 && zipNum <= 799) return "8a"; // South Central
    39|  if (zipNum >= 800 && zipNum <= 899) return "5b"; // Mountain West
