    57|    firstFrostMonth = 10; firstFrostDay = 1;
    58|    zone = "5b";
    59|  } else if (zipNum >= 100 && zipNum <= 199) { // Mid-Atlantic
    60|    lastFrostMonth = 4; lastFrostDay = 20;
    61|    firstFrostMonth = 10; firstFrostDay = 15;
    62|    zone = "6b";
    63|  } else if (zipNum >= 200 && zipNum <= 299) { // VA, Carolinas
    64|    lastFrostMonth = 4; lastFrostDay = 5;
    65|    firstFrostMonth = 11; firstFrostDay = 1;
    66|    zone = "7b";
    67|  } else if (zipNum >= 300 && zipNum <= 399) { // Deep South
    68|    lastFrostMonth = 3; lastFrostDay = 15;
    69|    firstFrostMonth = 11; firstFrostDay = 15;
    70|    zone = "8b";
