     9|  --bg-secondary: #373e42;
    10|  --text-primary: #E8D3BE;
    11|  --text-secondary: #b5a595;
    12|  --border-primary: #d35400;
    13|  --shadow-color: rgba(0, 0, 0, 0.6);
    14|  --accent: #ff7300;
    15|  --terminal-glow: rgba(163, 193, 173, 0.15);
    16|  
    17|  --font-mono: 'Courier New', Courier, monospace;
    18|  --font-hand: 'Caveat', cursive;
    19|}
    20|
    21|.dark {
    22|  --bg-primary: #1c1917;
    23|  --bg-secondary: #292524;
    24|  --text-primary: #e8e6e1;
    25|  --text-secondary: #a8a29e;
    26|  --border-primary: #d35400;
    27|  --shadow-color: rgba(0,0,0,0.5);
    28|  --accent: #ff7300;
    29|}
    30|
    31|* {
    32|  box-sizing: border-box;
    33|}
    34|
    35|body {
    36|  margin: 0;
    37|  font-family: var(--font-mono);
    38|  -webkit-font-smoothing: antialiased;
    39|  -moz-osx-font-smoothing: grayscale;
    40|  background-color: var(--bg-primary);
    41|  color: var(--text-primary);
    42|  transition: background-color 0.2s ease, color 0.2s ease;
    43|  line-height: 1.6;
    44|  position: relative;
    45|  image-rendering: crisp-edges;
    46|  text-shadow: 0.5px 0.5px 1px rgba(0,0,0,0.4);
    47|}
    48|
    49|code {
    50|  font-family: source-code-pro, Menlo, Monaco, Consolas, 'Courier New', monospace;
    51|}
    52|
    53|/* Brutalist Block (Weathered Field Manual Style) */
    54|.brutalist-block {
    55|  background-color: var(--bg-secondary);
    56|  color: var(--text-primary);
    57|  border: var(--border-weight, 2px) solid var(--border-primary);
    58|  box-shadow: 4px 4px 0px 0px var(--shadow-color);
    59|  transition: all 0.2s ease;
    60|}
    61|
    62|.brutalist-block:hover {
    63|  box-shadow: 6px 6px 0px var(--shadow-color);
    64|}
    65|
    66|.dark .brutalist-block {
    67|  background-color: #000000;
    68|  border-color: var(--border-primary);
    69|}
    70|
    71|/* Shadows */
    72|.shadow-brutalist-lg {
    73|  box-shadow: 8px 8px 0px 0px var(--shadow-color);
    74|}
    75|
    76|/* Backdrop blur */
    77|.backdrop-blur-sm {
    78|  backdrop-filter: blur(2px);
    79|}
    80|
    81|/* Animations */
    82|@keyframes pulse {
    83|  0%, 100% { opacity: 1; }
    84|  50% { opacity: .5; }
    85|}
    86|
    87|.animate-pulse {
    88|  animation: pulse 2s cubic-bezier(0.4, 0, 0.6, 1) infinite;
    89|}
    90|
    91|/* Smooth transitions */
    92|.transition-smooth {
    93|  transition: all 0.15s ease-in-out;
    94|}
    95|
    96|/* Lucide icons */
    97|svg {
    98|  display: inline-block;
    99|  vertical-align: middle;
   100|}
   101|
   102|/* Canvas overlay - scoped to avoid breaking STL viewer */
   103|canvas:not(.interactive) {
   104|  pointer-events: none;
   105|}
   106|
   107|/* Focus-visible styles for accessibility */
   108|:focus-visible {
   109|  outline: 2px solid var(--accent);
   110|  outline-offset: 2px;
   111|}
   112|
   113|/* Respect reduced motion preferences */
   114|@media (prefers-reduced-motion: reduce) {
   115|  *, *::before, *::after {
   116|    animation-duration: 0.01ms !important;
   117|    animation-iteration-count: 1 !important;
   118|    transition-duration: 0.01ms !important;
   119|    scroll-behavior: auto !important;
   120|  }
   121|}
   122|
   123|/* Selection */
   124|::selection {
   125|  background-color: var(--accent);
   126|  color: #ffffff;
   127|}
   128|
   129|/* Scrollbar styling */
   130|::-webkit-scrollbar {
   131|  width: 10px;
   132|}
   133|
   134|::-webkit-scrollbar-track {
   135|  background: var(--bg-primary);
   136|}
   137|
   138|::-webkit-scrollbar-thumb {
   139|  background: var(--accent);
   140|  border: 2px solid var(--bg-primary);
   141|}
   142|
   143|/* Tactile Dymo Label Effect */
   144|.dymo-label {
   145|  background: #111;
   146|  color: #eee;
   147|  padding: 4px 12px;
   148|  border-radius: 2px;
   149|  text-transform: uppercase;
   150|  font-weight: bold;
   151|  letter-spacing: 2px;
   152|  box-shadow: inset 1px 1px 1px rgba(255,255,255,0.1), 2px 2px 4px rgba(0,0,0,0.5);
   153|  border: 1px solid #333;
   154|  display: inline-block;
   155|  font-size: 0.75rem;
   156|  transition: transform 0.1s ease;
   157|}
   158|
   159|.dymo-label:hover {
   160|  transform: translate(1px, 1px);
   161|  box-shadow: inset 1px 1px 1px rgba(255,255,255,0.1), 1px 1px 2px rgba(0,0,0,0.5);
   162|}
   163|
   164|.dymo-label:active {
   165|  transform: translateY(1px);
   166|  box-shadow: inset 1px 1px 1px rgba(255,255,255,0.05), 1px 1px 2px rgba(0,0,0,0.5);
   167|}
   168|
   169|/* Heavy "Concrete" Border */
   170|.field-station-box {
   171|  padding: 2rem;
   172|  position: relative;
   173|  background: rgba(0,0,0,0.2);
   174|}
   175|
   176|.field-station-box::after {
   177|  content: "REF_07G";
   178|  position: absolute;
   179|  bottom: -10px;
   180|  right: 20px;
   181|  background: var(--bg-secondary);
   182|  padding: 0 8px;
   183|  font-size: 0.7rem;
   184|  color: var(--text-secondary);
   185|  border: 1px solid var(--border-primary);
   186|  z-index: 30;
   187|}
   188|
   189|/* Marginalia Styling */
   190|.marginalia {
   191|  font-family: 'Caveat', cursive;
   192|  color: var(--accent);
   193|  font-size: 1.1rem;
   194|  position: absolute;
   195|  opacity: 0.9;
   196|  pointer-events: none;
   197|  line-height: 1.1;
   198|  transform: rotate(-2deg);
   199|  max-width: 150px;
   200|  text-shadow: 1px 1px 0px rgba(0,0,0,0.1);
   201|  z-index: 50;
   202|}
   203|
   204|/* The 'Condensation Sizzle' Glitch */
   205|@keyframes condensation-glitch {
   206|  0%, 100% { transform: translate(0); filter: blur(0) contrast(1); opacity: 1; }
   207|  1.5% { transform: translate(-3px, 2px); filter: blur(1.2px) contrast(1.6) hue-rotate(8deg); }
   208|  3%   { transform: translate(4px, -3px); filter: blur(0.8px); }
   209|  4.5% { transform: translate(-1px, 1px); filter: contrast(1.3); }
   210|  6%   { transform: translate(0); opacity: 0.92; }
   211|}
   212|
   213|@keyframes scan-flash {
   214|  0% { opacity: 0; top: 0; }
   215|  1% { opacity: 0.3; top: 50%; }
   216|  2% { opacity: 0; top: 100%; }
   217|  100% { opacity: 0; top: 100%; }
   218|}
   219|
   220|@keyframes drip {
   221|  0% { transform: translateY(-100%); }
   222|  100% { transform: translateY(200%); }
   223|}
   224|
   225|.terminal-container {
   226|  animation: condensation-glitch 28s infinite ease-in-out;
   227|  position: relative;
   228|  overflow: hidden;
   229|}
   230|
   231|/* Add dripping condensation effect */
   232|.terminal-container::after {
   233|  content: "";
   234|  position: absolute;
   235|  top: 0; left: 0; right: 0;
   236|  height: 100%;
   237|  background: linear-gradient(transparent, rgba(163,193,173,0.08) 20%, transparent 40%);
   238|  animation: drip 18s linear infinite;
   239|  pointer-events: none;
   240|}
   241|
   242|/* Horizontal 'Short-Circuit' line */
   243|.terminal-container::before {
   244|  content: "";
   245|  position: absolute;
   246|  top: 0;
   247|  left: 0;
   248|  width: 100%;
   249|  height: 2px;
   250|  background: var(--accent);
   251|  opacity: 0;
   252|  z-index: 20;
   253|  pointer-events: none;
   254|  animation: scan-flash 35s infinite;
   255|}
   256|
   257|/* Global Print Styles */
   258|@media print {
   259|  body {
   260|    background: white !important;
   261|    color: black !important;
   262|  }
   263|  * {
   264|    box-shadow: none !important;
   265|  }
   266|}
