{"content": "     1|"use client";
     2|
     3|import { useState, useEffect } from "react";
     4|import { Box, Sun, Moon, ShoppingCart, Menu, X, Zap, ZapOff } from "lucide-react";
     5|import { useCart } from "@/app/context/CartContext";
     6|import Link from "next/link";
     7|import Badge from "@/components/ui/Badge";
     8|import DymoLabel from "@/components/ui/DymoLabel";
     9|
    10|export default function Navigation() {
    11|  const [isDark, setIsDark] = useState(false);
    12|  const [lowFX, setLowFX] = useState(false);
    13|  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
    14|  const { totalItems, isRequisitionSubmitted } = useCart();
    15|
    16|  useEffect(() => {
    17|    // Load preferences from localStorage
    18|    const savedDark = localStorage.getItem("hl_dark_mode");
    19|    if (savedDark) {
    20|      const dark = JSON.parse(savedDark);
    21|      setIsDark(dark);
    22|      if (dark) document.documentElement.classList.add("dark");
    23|    }
    24|    
    25|    const savedLowFX = localStorage.getItem("hl_ui_low_fx");
    26|    if (savedLowFX === "true") setLowFX(true);
    27|  }, []);
    28|
    29|  const toggleDarkMode = () => {
    30|    const newValue = !isDark;
    31|    setIsDark(newValue);
    32|    document.documentElement.classList.toggle("dark", newValue);
    33|    localStorage.setItem("hl_dark_mode", JSON.stringify(newValue));
    34|  };
    35|
    36|  const toggleLowFX = () => {
    37|    const newValue = !lowFX;
    38|    setLowFX(newValue);
    39|    localStorage.setItem("hl_ui_low_fx", String(newValue));
    40|    // Trigger event for VisualEffects component
    41|    window.dispatchEvent(new Event("hl-toggle-fx"));
    42|  };
    43|
    44|  const requisitionStatus = isRequisitionSubmitted ? "SUBMITTED" : "PENDING";
    45|
    46|  return (
    47|    <nav className="border-b-2 border-border-primary bg-background-secondary text-foreground-primary sticky top-0 z-50 transition-colors duration-300">
    48|      <div className="max-w-7xl mx-auto px-4 py-3 flex justify-between items-center">
    49|        {/* Logo */}
    50|        <Link href="/" className="text-xl font-bold tracking-tight cursor-pointer flex items-center gap-2 group select-none">
    51|          <div className="w-8 h-8 bg-accent text-white flex items-center justify-center group-hover:invert transition-all">
    52|            <Box size={20} />
    53|          </div>
    54|          <span className="hidden sm:inline">HOMESTEADER_LABS</span>
    55|          <span className="sm:hidden">HL_SYS</span>
    56|        </Link>
    57|
    58|        {/* Desktop Navigation */}
    59|        <div className="hidden md:flex gap-4 text-sm items-center">
    60|          <Link href="/shop/">
    61|            <DymoLabel className="opacity-80 hover:opacity-100 scale-90">SHOP</DymoLabel>
    62|          </Link>
    63|          <Link href="/archive/">
    64|            <DymoLabel className="opacity-80 hover:opacity-100 scale-90">ARCHIVE</DymoLabel>
    65|          </Link>
    66|          <Link href="/tools/planting-calendar/">
    67|            <DymoLabel className="opacity-80 hover:opacity-100 scale-90">PLANTING</DymoLabel>
    68|          </Link>
    69|          <Link href="/tools/fabrication/">
    70|            <DymoLabel className="opacity-80 hover:opacity-100 scale-90">FABRICATION</DymoLabel>
    71|          </Link>
    72|          <Link href="/tools/weather/">
    73|            <DymoLabel className="opacity-80 hover:opacity-100 scale-90">WEATHER</DymoLabel>
    74|          </Link>
    75|
    76|          <button
    77|            onClick={toggleDarkMode}
    78|            className="p-2 border border-border-primary hover:bg-accent hover:text-white transition-all"
    79|            aria-label={isDark ? "Switch to light mode" : "Switch to dark mode"}
    80|          >
    81|            {isDark ? <Sun size={16} /> : <Moon size={16} />}
    82|          </button>
    83|          
    84|          <button
    85|            onClick={toggleLowFX}
    86|            className={`p-2 border transition-all ${lowFX ? 'bg-accent/20 text-accent' : 'border-border-primary hover:bg-accent hover:text-white'}`}
    87|            aria-label={lowFX ? "Enable visual effects" : "Disable visual effects (Low FX mode)"}
    88|            title={lowFX ? "Low FX Mode: ON" : "Low FX Mode: OFF"}
    89|          >
    90|            {lowFX ? <ZapOff size={16} /> : <Zap size={16} />}
    91|          </button>
    92|        </div>
    93|
    94|        {/* Requisition & Mobile Toggle */}
    95|        <div className="flex items-center gap-4">
    96|          <Link 
    97|            href="/requisition/"
    98|            className="flex items-center gap-2 border-2 border-border-primary px-3 py-1 hover:bg-accent hover:text-white transition-colors bg-background-primary/30"
    99|          >
   100|            <ShoppingCart size={14} />
   101|            <span className="text-[10px] hidden lg:inline font-mono">REQ_LOG:</span>
   102|            <span className="font-bold text-xs">{totalItems.toString().padStart(2, "0")}</span>
   103|            <Badge 
   104|              variant="solid" 
   105|              className={`text-[7px] px-1 py-0 leading-tight ${isRequisitionSubmitted ? 'bg-green-600 border-green-600' : 'bg-accent border-accent'}`}
   106|            >
   107|              {requisitionStatus}
   108|            </Badge>
   109|          </Link>
   110|
   111|          <button
   112|            onClick={() => setMobileMenuOpen(!mobileMenuOpen)}
   113|            className="md:hidden p-1 border border-border-primary"
   114|            aria-label="Toggle menu"
   115|          >
   116|            {mobileMenuOpen ? <X size={20} /> : <Menu size={20} />}
   117|          </button>
   118|        </div>
   119|      </div>
   120|
   121|      {/* Mobile Navigation Dropdown */}
   122|      {mobileMenuOpen && (
   123|        <div className="md:hidden border-t-2 border-border-primary bg-background-secondary p-4 space-y-4 animate-in slide-in-from-top duration-200">
   124|          <div className="grid grid-cols-2 gap-3">
   125|            <Link href="/shop/" onClick={() => setMobileMenuOpen(false)}>
   126|              <DymoLabel className="w-full text-center">SHOP</DymoLabel>
   127|            </Link>
   128|            <Link href="/archive/" onClick={() => setMobileMenuOpen(false)}>
   129|              <DymoLabel className="w-full text-center">ARCHIVE</DymoLabel>
   130|            </Link>
   131|            <Link href="/tools/planting-calendar/" onClick={() => setMobileMenuOpen(false)}>
   132|              <DymoLabel className="w-full text-center">PLANTING</DymoLabel>
   133|            </Link>
   134|            <Link href="/tools/fabrication/" onClick={() => setMobileMenuOpen(false)}>
   135|              <DymoLabel className="w-full text-center">FABRICATION</DymoLabel>
   136|            </Link>
   137|            <Link href="/tools/weather/" onClick={() => setMobileMenuOpen(false)}>
   138|              <DymoLabel className="w-full text-center">WEATHER</DymoLabel>
   139|            </Link>
   140|          </div>
   141|          <div className="flex justify-between items-center pt-2 border-t border-border-primary/20 gap-4">
   142|            <div className="flex items-center gap-2">
   143|              <span className="text-xs font-mono opacity-50 uppercase">Theme:</span>
   144|              <button
   145|                onClick={toggleDarkMode}
   146|                className="flex items-center gap-2 px-4 py-1 border border-border-primary text-xs"
   147|              >
   148|                {isDark ? <><Sun size={14} /> LIGHT</> : <><Moon size={14} /> DARK</>}
   149|              </button>
   150|            </div>
   151|            <div className="flex items-center gap-2">
   152|              <span className="text-xs font-mono opacity-50 uppercase">FX:</span>
   153|              <button
   154|                onClick={toggleLowFX}
