     3|interface TypographyProps {
     4|  children: React.ReactNode;
     5|  className?: string;
     6|  as?: 'h1' | 'h2' | 'h3' | 'h4' | 'p' | 'span';
     7|  variant?: 'h1' | 'h2' | 'h3' | 'h4' | 'body' | 'small' | 'code';
