    10|
    11|const Typography = ({
    12|  children,
    13|  className = '',
    14|  as,
    15|  variant = 'body',
    16|  style,
    17|}: TypographyProps) => {
    18|  const Component = as || (variant.startsWith('h') ? (variant as React.ElementType) : variant === 'body' ? 'p' : 'span');
    19|
    20|  const variants = {
    21|    h1: "text-4xl md:text-6xl lg:text-7xl font-bold uppercase tracking-tight mb-6",
