    24|    h4: "text-lg font-bold uppercase mb-2",
    25|    body: "text-base md:text-lg leading-relaxed mb-4",
    26|    small: "text-sm text-foreground-secondary",
    27|    code: "font-mono bg-background-secondary px-1 py-0.5 rounded-sm text-sm",
    28|  };
    29|
    30|  return (
    31|    <Component className={`${variants[variant]} ${className}`} style={style}>
    32|      {children}
