{"content": "     1|export interface FilamentType {
     2|  id: string;
     3|  name: string;
     4|  pricePerKg: number;
     5|  density: number; // g/cm³
     6|  printTemp: string;
     7|  bedTemp: string;
     8|  description: string;
     9|}
    10|
    11|export interface PrintSettings {
    12|  infill: number; // 0-100%
    13|  layerHeight: number; // mm
    14|  wallCount: number;
    15|  supportEnabled: boolean;
    16|}
    17|
    18|export interface PrintEstimate {
    19|  volume: number; // cm³
    20|  weight: number; // grams
    21|  printTime: number; // minutes
    22|  materialCost: number; // dollars
    23|  serviceFee: number; // dollars
    24|  totalCost: number; // dollars
    25|}
    26|
    27|export const FILAMENT_TYPES: FilamentType[] = [
    28|  {
    29|    id: "pla",
    30|    name: "PLA",
    31|    pricePerKg: 20,
    32|    density: 1.24,
    33|    printTemp: "190-220°C",
    34|    bedTemp: "50-60°C",
    35|    description: "Easy to print, biodegradable. Best for prototypes and decorative items.",
    36|  },
    37|  {
    38|    id: "petg",
    39|    name: "PETG",
    40|    pricePerKg: 25,
    41|    density: 1.27,
    42|    printTemp: "220-250°C",
    43|    bedTemp: "70-80°C",
    44|    description: "Stronger than PLA, water resistant. Good for functional parts.",
    45|  },
    46|];
    47|
    48|export const DEFAULT_SETTINGS: PrintSettings = {
    49|  infill: 20,
    50|  layerHeight: 0.2,
    51|  wallCount: 3,
    52|  supportEnabled: false,
    53|};
    54|
    55|// Calculate print estimate from model volume
    56|export function calculatePrintEstimate(
    57|  volumeCm3: number,
    58|  filament: FilamentType,
    59|  settings: PrintSettings
    60|): PrintEstimate {
    61|  // Adjust volume for infill (walls are always 100%)
    62|  // Simplified: assume infill affects internal volume
    63|  const infillFactor = settings.infill / 100;
    64|  const adjustedVolume = volumeCm3 * (0.4 + 0.6 * infillFactor);
    65|
    66|  // Calculate weight
    67|  const weight = adjustedVolume * filament.density;
    68|
    69|  // Estimate print time (very rough estimate)
    70|  // Based on: volume, layer height, typical print speeds
    71|  const baseMinutesPerCm3 = 8; // baseline
    72|  const layerHeightFactor = 0.2 / settings.layerHeight; // finer = slower
    73|  const printTime = adjustedVolume * baseMinutesPerCm3 * layerHeightFactor;
    74|
    75|  // Material cost
    76|  const materialCost = (weight / 1000) * filament.pricePerKg;
    77|
    78|  // Service fee (labor, electricity, machine wear)
    79|  const hourlyRate = 5; // $5/hour for machine time
    80|  const serviceFee = (printTime / 60) * hourlyRate;
    81|
    82|  // Minimum fee
    83|  const minFee = 5;
    84|  const adjustedServiceFee = Math.max(serviceFee, minFee);
    85|
    86|  const totalCost = materialCost + adjustedServiceFee;
    87|
    88|  return {
    89|    volume: Math.round(adjustedVolume * 100) / 100,
    90|    weight: Math.round(weight * 10) / 10,
    91|    printTime: Math.round(printTime),
    92|    materialCost: Math.round(materialCost * 100) / 100,
    93|    serviceFee: Math.round(adjustedServiceFee * 100) / 100,
    94|    totalCost: Math.round(totalCost * 100) / 100,
    95|  };
    96|}
    97|
    98|// Format minutes to hours and minutes
    99|export function formatPrintTime(minutes: number): string {
   100|  if (minutes < 60) return `${minutes} min`;
   101|  const hours = Math.floor(minutes / 60);
   102|  const mins = minutes % 60;
   103|  return mins > 0 ? `${hours}h ${mins}m` : `${hours}h`;
   104|}
