    15|  excerpt: string;
    16|  content: string;
    17|}
    18|
    19|export function getAllPosts(): Post[] {
    20|  // Check if directory exists
    21|  if (!fs.existsSync(postsDirectory)) {
    22|    return [];
    23|  }
    24|
    25|  const fileNames = fs.readdirSync(postsDirectory);
    26|  const allPostsData = fileNames
    27|    .filter((fileName) => fileName.endsWith('.mdx'))
    28|    .map((fileName) => {
    29|      // Remove ".mdx" from file name to get slug
    30|      const slug = fileName.replace(/\.mdx$/, '');
    31|
    32|      // Read markdown file as string
    33|      const fullPath = path.join(postsDirectory, fileName);
    34|      const fileContents = fs.readFileSync(fullPath, 'utf8');
    35|
    36|      // Use gray-matter to parse the post metadata section
    37|      const { data, content } = matter(fileContents);
    38|
    39|      // Combine the data with the slug
    40|      return {
    41|        slug,
    42|        title: data.title || '',
    43|        description: data.description || '',
    44|        date: data.date || '',
    45|        author: data.author || '',
    46|        tags: data.tags || [],
    47|        category: data.category || '',
    48|        excerpt: data.excerpt || '',
    49|        content,
    50|      };
    51|    });
    52|
    53|  // Sort posts by date
    54|  return allPostsData.sort((a, b) => {
    55|    if (a.date < b.date) {
    56|      return 1;
    57|    } else {
    58|      return -1;
    59|    }
    60|  });
    61|}
    62|
    63|export function getPostBySlug(slug: string): Post | null {
    64|  try {
    65|    const fullPath = path.join(postsDirectory, `${slug}.mdx`);
    66|    
    67|    // Check if file exists
    68|    if (!fs.existsSync(fullPath)) {
    69|      return null;
    70|    }
    71|
    72|    const fileContents = fs.readFileSync(fullPath, 'utf8');
    73|    const { data, content } = matter(fileContents);
    74|
    75|    return {
    76|      slug,
    77|      title: data.title || '',
    78|      description: data.description || '',
    79|      date: data.date || '',
    80|      author: data.author || '',
    81|      tags: data.tags || [],
    82|      category: data.category || '',
    83|      excerpt: data.excerpt || '',
    84|      content,
    85|    };
    86|  } catch {
    87|    return null;
    88|  }
    89|}
    90|
    91|export function getAllSlugs(): string[] {
    92|  if (!fs.existsSync(postsDirectory)) {
    93|    return [];
    94|  }
    95|
    96|  const fileNames = fs.readdirSync(postsDirectory);
    97|  return fileNames
    98|    .filter((fileName) => fileName.endsWith('.mdx'))
    99|    .map((fileName) => fileName.replace(/\.mdx$/, ''));
   100|}
   101|
   102|export function getAllTags(): string[] {
   103|  const posts = getAllPosts();
   104|  const tags = new Set<string>();
   105|  
   106|  posts.forEach((post) => {
