{"code": "from hermes_tools import search_files, patch, read_file
import os

# Find all tsx files with tiny text
result = search_files(r'text-\[(7|8|9|10)px\]', target='content', path='.', file_glob='*.tsx', limit=200)
files = sorted(set(m['path'] for m in result.get('matches', [])))
print(f"Files to patch: {len(files)}")
for f in files:
    print(f"  {f}")

# Apply replacements - order matters: 10px first, then 9, 8, 7 to avoid double-replace
replacements = [
    ('text-[10px]', 'text-xs'),
    ('text-[9px]', 'text-[11px]'),
    ('text-[8px]', 'text-[10px]'),
    ('text-[7px]', 'text-[9px]'),
]

changed_files = set()
for old, new in replacements:
    for filepath in files:
        try:
            r = patch(filepath, old, new, replace_all=True)
            if r.get('success'):
                changed_files.add(filepath)
        except Exception:
            pass

print(f"\nPatched {len(changed_files)} files")
"}

